   439→	// When the transaction contains write operations, we use ReadTx instead of
   440→	// ConcurrentReadTx to avoid extra overhead of copying buffer.
   441→	var txn mvcc.TxnWrite
   442→	if isWrite && a.s.Cfg.ExperimentalTxnModeWriteWithSharedBuffer {
   443→		txn = mvcc.NewReadOnlyTxnWrite(a.s.KV().Read(mvcc.SharedBufReadTxMode, trace))
   444→	} else {
   445→		txn = mvcc.NewReadOnlyTxnWrite(a.s.KV().Read(mvcc.ConcurrentReadTxMode, trace))
   446→	}
   447→
   448→	var txnPath []bool
   449→	trace.StepWithFunction(
   450→		func() {
   451→			txnPath = compareToPath(txn, rt)
   452→		},
   453→		"compare",
   454→	)
   455→
   456→	if isWrite {
   457→		trace.AddField(traceutil.Field{Key: "read_only", Value: false})
   458→		if _, err := checkRequests(txn, rt, txnPath, a.checkPut); err != nil {
   459→			txn.End()
   460→			return nil, nil, err
   461→		}
   462→	}
   463→	if _, err := checkRequests(txn, rt, txnPath, a.checkRange); err != nil {
   464→		txn.End()
   465→		return nil, nil, err
   466→	}
   467→	trace.Step("check requests")
   468→	txnResp, _ := newTxnResp(rt, txnPath)
   469→
   470→	// When executing mutable txn ops, etcd must hold the txn lock so
   471→	// readers do not see any intermediate results. Since writes are
   472→	// serialized on the raft loop, the revision in the read view will
   473→	// be the revision of the write txn.
   474→	if isWrite {
   475→		txn.End()
   476→		txn = a.s.KV().Write(trace)
   477→	}
   478→	_, err := a.applyTxn(ctx, txn, rt, txnPath, txnResp)
   479→	if err != nil {
   480→		if isWrite {
   481→			// CAUTION: When a txn performing write operations starts, we always expect it to be successful.
   482→			// If a write failure is seen we SHOULD NOT try to recover the server, but crash with a panic to make the failure explicit.
   483→			// Trying to silently recover (e.g by ignoring the failed txn or calling txn.End() early) poses serious risks:
   484→			// - violation of transaction atomicity if some write operations have been partially executed
   485→			// - data inconsistency across different etcd members if they applied the txn asymmetrically
   486→			lg.Panic("unexpected error during txn with writes", zap.Error(err))
